private struct ChatGPTTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum ChatGPTScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("chat") || t.contains("discover") || t.contains("histor"):
            ChatGPTChatScreen()
        default:
            ChatGPTGenericListScreen(title: tab)
        }
    }
}
