private struct ChatGPTChatScreen: View {
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 12) {
                    ForEach(ChatGPTDemoData.messages) { msg in
                        if msg.isUser { ChatGPTUserBubble(text: msg.text, accent: ChatGPTTokens.gptLegacyGreen) }
                        else { ChatGPTAssistantBubble(text: msg.text, surface: ChatGPTTokens.gptUserBubbleLight) }
                    }
                }.padding()
            }.background(ChatGPTTokens.gptCanvas.ignoresSafeArea())
            HStack(spacing: 12) {
                TextField("Message ChatGPT…", text: $draft, axis: .vertical).padding(10).background(RoundedRectangle(cornerRadius: 20).fill(ChatGPTTokens.gptUserBubbleLight))
                Button {} label: { Image(systemName: "arrow.up.circle.fill").font(.title2).foregroundStyle(ChatGPTTokens.gptLegacyGreen) }
            }.padding().background(.bar)
        }
    }
}

private struct ChatGPTUserBubble: View {
    let text: String; let accent: Color
    var body: some View { HStack { Spacer(minLength: 48); Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(accent.opacity(0.15))) } }
}

private struct ChatGPTAssistantBubble: View {
    let text: String; let surface: Color
    var body: some View { HStack { Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(surface)); Spacer(minLength: 48) } }
}

private struct ChatGPTChatMsg: Identifiable { let id = UUID(); let text: String; let isUser: Bool }
private enum ChatGPTDemoData {
    static let messages: [ChatGPTChatMsg] = [
        .init(text: "Explique-moi le métro parisien", isUser: true),
        .init(text: "Le métro parisien compte 16 lignes numérotées. La ligne 1 traverse Paris d'ouest en est.", isUser: false),
        .init(text: "Quel ticket acheter ?", isUser: true),
        .init(text: "Pour un touriste, le pass Navigo Jour ou des tickets t+ sont les options les plus courantes.", isUser: false),
    ]
}

private struct ChatGPTGenericListScreen: View {
    let title: String
    var body: some View {
        NavigationStack {
            List(0..<8, id: \.self) { i in
                HStack {
                    RoundedRectangle(cornerRadius: 8).fill(ChatGPTTokens.gptLegacyGreen.opacity(0.15)).frame(width: 44, height: 44)
                    VStack(alignment: .leading) {
                        Text("\(title) \(i + 1)").font(.system(size: 17, weight: .semibold))
                        Text("Mis à jour récemment").font(.system(size: 14)).foregroundStyle(.secondary)
                    }
                }
            }
            .navigationTitle(title)
        }
    }
}
